import React from 'react';

const Home = () => {
  return (
    <div className="home">
      <h1>Welcome to Jet Nozzle Flow System</h1>
      <p>Monitor and analyze jet nozzle flow dynamics in real-time.</p>
      <section className="features">
        <h2>Features</h2>
        <ul>
          <li>Real-time sensor monitoring</li>
          <li>Flow analysis and visualization</li>
          <li>Nozzle design optimization</li>
          <li>Historical data tracking</li>
        </ul>
      </section>
    </div>
  );
};

export default Home;
